130: func (s *ServiceImpl) QueryDataNew(ctx context.Context, user identity.Requester, skipDSCache bool, reqDTO dtos.MetricRequest) (*backend.QueryDataResponse, error) {
131: 	return s.queryData(ctx, user, skipDSCache, reqDTO, true)
132: }
