36: func newClientV2(descriptor PluginDescriptor, logger log.Logger, rpcClient plugin.ClientProtocol) (*ClientV2, error) {
37: 	rawDiagnostics, err := rpcClient.Dispense("diagnostics")
38: 	if err != nil {
39: 		return nil, err
