62: 	rawStream, err := rpcClient.Dispense("stream")
63: 	if err != nil {
64: 		return nil, err
65: 	}
66: 
67: 	rawRenderer, err := rpcClient.Dispense("renderer")
68: 	if err != nil {
69: 		return nil, err
70: 	}
71: 
72: 	c := &ClientV2{}
73: 	if rawDiagnostics != nil {
74: 		if diagnosticsClient, ok := rawDiagnostics.(grpcplugin.DiagnosticsClient); ok {
75: 			c.DiagnosticsClient = diagnosticsClient
76: 		}
77: 	}
78: 
79: 	if rawResource != nil {
80: 		if resourceClient, ok := rawResource.(grpcplugin.ResourceClient); ok {
81: 			c.ResourceClient = resourceClient
82: 		}
83: 	}
84: 
85: 	if rawData != nil {
86: 		if dataClient, ok := rawData.(grpcplugin.DataClient); ok {
87: 			c.DataClient = dataClient
88: 		}
89: 	}
90: 
91: 	if rawAdmission != nil {
92: 		if admissionClient, ok := rawAdmission.(grpcplugin.AdmissionClient); ok {
93: 			c.AdmissionClient = admissionClient
94: 		}
95: 	}
96: 
97: 	if rawConversion != nil {
98: 		if conversionClient, ok := rawConversion.(grpcplugin.ConversionClient); ok {
99: 			c.ConversionClient = conversionClient
100: 		}
101: 	}
102: 
103: 	if rawStream != nil {
104: 		if streamClient, ok := rawStream.(grpcplugin.StreamClient); ok {
105: 			c.StreamClient = streamClient
106: 		}
107: 	}
108: 
109: 	if rawRenderer != nil {
110: 		if rendererPlugin, ok := rawRenderer.(pluginextensionv2.RendererPlugin); ok {
111: 			c.RendererPlugin = rendererPlugin
112: 		}
113: 	}
114: 
115: 	if descriptor.startRendererFn != nil {
116: 		if err := descriptor.startRendererFn(descriptor.pluginID, c.RendererPlugin, logger); err != nil {
117: 			return nil, err
118: 		}
119: 	}
120: 
121: 	return c, nil
122: }
