124: func (c *ClientV2) CollectMetrics(ctx context.Context, req *backend.CollectMetricsRequest) (*backend.CollectMetricsResult, error) {
125: 	if c.DiagnosticsClient == nil {
126: 		return &backend.CollectMetricsResult{}, nil
127: 	}
128: 
129: 	protoResp, err := c.DiagnosticsClient.CollectMetrics(ctx, backend.ToProto().CollectMetricsRequest(req))
